INSERT INTO `iyque_robot_sub` (`id`, `annexContent`, `delFlag`, `msgTitle`, `msgType`, `robotId`, `sendTime`) VALUES
(7600001, '{"content": "【每日语录 · 格雷厄姆】价格是你付出的，价值才是你得到的。"}', 0, '每日语录推送 1', 'text', 7500001, '2024-01-02 14:27:17'),
(7600002, '{"content": "【每日语录 · 巴菲特】投资的第一条原则是永远不要亏损；第二条原则是永远不要忘记第一条。"}', 0, '每日语录推送 2', 'text', 7500002, '2024-02-26 16:09:10'),
(7600003, '{"content": "【每日语录 · 巴菲特】买股票就是买公司。"}', 0, '每日语录推送 3', 'text', 7500003, '2026-04-26 14:35:07'),
(7600004, '{"content": "【每日语录 · 巴菲特】我们喜欢简单的生意，不喜欢有太多变量的生意。"}', 0, '每日语录推送 4', 'text', 7500004, '2026-05-10 05:54:57'),
(7600005, '{"content": "【每日语录 · 芒格】反过来想，总是反过来想。"}', 0, '每日语录推送 5', 'text', 7500005, '2025-10-12 07:24:10'),
(7600006, '{"content": "【每日语录 · 芒格】宏观是我们必须承受的，微观才是我们能有所作为的。"}', 0, '每日语录推送 6', 'text', 7500006, '2024-03-05 06:43:49'),
(7600007, '{"content": "【每日语录 · 芒格】得到你想要的东西的最保险办法，就是让自己配得上它。"}', 0, '每日语录推送 7', 'text', 7500007, '2025-01-22 08:59:11'),
(7600008, '{"content": "【每日语录 · 彼得·林奇】买你熟悉的股票，避开你不熟悉的。"}', 0, '每日语录推送 8', 'text', 7500008, '2024-01-07 04:20:39'),
(7600009, '{"content": "【每日语录 · 彼得·林奇】如果连一家公司的业务你都无法用一支蜡笔说清楚，那就别买。"}', 0, '每日语录推送 9', 'text', 7500009, '2024-04-05 14:26:59'),
(7600010, '{"content": "【每日语录 · 费雪】投资的最好时机是找到伟大企业时。"}', 0, '每日语录推送 10', 'text', 7500010, '2025-11-11 16:38:52'),
(7600011, '{"content": "【每日语录 · 邓普顿】在极度悲观的时候买入，在极度乐观的时候卖出。"}', 0, '每日语录推送 11', 'text', 7500011, '2025-09-27 05:56:46'),
(7600012, '{"content": "【每日语录 · 段永平】做对的事情，把事情做对。"}', 0, '每日语录推送 12', 'text', 7500012, '2024-06-22 18:36:13'),
(7600013, '{"content": "【每日语录 · 段永平】本分比聪明重要。"}', 0, '每日语录推送 13', 'text', 7500013, '2026-05-19 13:30:21'),
(7600014, '{"content": "【每日语录 · 段永平】长期视角看，好生意最终会给股东回报。"}', 0, '每日语录推送 14', 'text', 7500014, '2026-05-14 13:46:22'),
(7600015, '{"content": "【每日语录 · 林园】看得见摸得着的消费股，才是能陪你一辈子的股票。"}', 0, '每日语录推送 15', 'text', 7500015, '2024-10-01 06:54:01'),
(7600016, '{"content": "【每日语录 · 但斌】时间的玫瑰只献给坚守的人。"}', 0, '每日语录推送 16', 'text', 7500016, '2026-05-01 18:01:17'),
(7600017, '{"content": "【每日语录 · 章盟主】情绪是短线的燃料，但价值是长线的锚。"}', 0, '每日语录推送 17', 'text', 7500017, '2024-11-12 18:32:59'),
(7600018, '{"content": "【每日语录 · 李录】在中国做价值投资，需要更长的时间维度。"}', 0, '每日语录推送 18', 'text', 7500018, '2025-06-06 19:11:20'),
(7600019, '{"content": "【每日语录 · 赵丹阳】绝对收益是价值投资者的自我修养。"}', 0, '每日语录推送 19', 'text', 7500019, '2024-01-27 20:01:21'),
(7600020, '{"content": "【每日语录 · 格雷厄姆】价格是你付出的，价值才是你得到的。"}', 0, '每日语录推送 20', 'text', 7500020, '2024-10-22 17:57:29'),
